const body = $input.first().json.body;
const now = new Date().toISOString();
const id = 'ART30-' + Date.now();

return [{
  json: {
    id,
    erstellt_am: now,
    verantwortlicher: body.verantwortlicher || 'Nicht angegeben',
    zweck: body.zweck,
    kategorien_betroffener: body.kategorien_betroffener || [],
    datenkategorien: body.datenkategorien || [],
    empfaenger: body.empfaenger || [],
    drittland_transfer: body.drittland_transfer || false,
    loeschfrist: body.loeschfrist || 'Nicht definiert',
    technische_massnahmen: body.technische_massnahmen || [],
    rechtsgrundlage: body.rechtsgrundlage || 'Art. 6 Abs. 1 lit. a DSGVO',
    status: 'aktiv',
    markdown: `## ${id}\n**Zweck**: ${body.zweck}\n**Rechtsgrundlage**: ${body.rechtsgrundlage || 'Art. 6 Abs. 1 lit. a DSGVO'}\n**Erstellt**: ${now}\n**Löschfrist**: ${body.loeschfrist || 'Nicht definiert'}`
  }
}];
